ALGORITHM ANNIHILATE(f, δ):
  (δ_s, δ_d, δ_q) := δ

  // Schema delta annihilation rules
  if f == SELECT:
    for each ADD_COLUMN(c,τ,p,d) in δ_s:
      if c ∉ SELECT_COLUMNS(f) then continue
      else return false
    return δ_d == 0_D and δ_q == ⊥_Q

  if f == JOIN:
    // Empty input annihilates join
    if (δ_d contains INSERT(∅)) or (δ_d contains DELETE(all_tuples)) then return true
    // Schema changes to non-join columns don't affect output
    join_columns := EXTRACT_JOIN_COLUMNS(f)
    for each schema_op in δ_s:
      if AFFECTS_COLUMNS(schema_op, join_columns) then return false
    return δ_d == 0_D and δ_q == ⊥_Q

  if f == FILTER:
    // Unsatisfiable predicate annihilates
    if PREDICATE_UNSATISFIABLE(f, δ_d) then return true
    // Schema changes to non-predicate columns don't affect filtering
    pred_columns := EXTRACT_PREDICATE_COLUMNS(f)
    for each schema_op in δ_s:
      if AFFECTS_COLUMNS(schema_op, pred_columns) then return false
    return δ_d == 0_D and δ_q == ⊥_Q

  if f == GROUP_BY:
    group_cols := EXTRACT_GROUP_COLUMNS(f)
    agg_cols := EXTRACT_AGGREGATE_COLUMNS(f)
    // Changes to non-group, non-aggregate columns annihilate
    for each schema_op in δ_s:
      affected_cols := AFFECTED_COLUMNS(schema_op)
      if affected_cols ∩ (group_cols ∪ agg_cols) ≠ ∅ then return false
    // Zero-contribution data deltas for sum/count aggregates
    if ALL_AGGREGATES_ZERO_CONTRIBUTION(f, δ_d) then return true
    return δ_d == 0_D and δ_q == ⊥_Q

  if f == UNION:
    return δ_s == ε_S and δ_d == 0_D and δ_q == ⊥_Q

  // Conservative default: no annihilation for unrecognized operators
  return false

ALGORITHM DP_REPAIR(G, Δ):
  // Memoization table: node → (cost, repair_actions)
  memo := Map<Node, (Float, Set<RepairAction>)>()

  // Post-order traversal for bottom-up DP
  post_order := REVERSE_TOPOLOGICAL_SORT(G)

  for each v ∈ post_order do
    δ_v := Δ[v]  // Propagated delta at node v

    if δ_v == (ε_S, 0_D, ⊥_Q):
      // No delta: no repair needed
      memo[v] := (0.0, ∅)
      continue

    if ANNIHILATE(OPERATOR(v), δ_v):
      // Delta annihilates: no repair needed
      memo[v] := (0.0, ∅)
      continue

    // Option 1: Repair this node directly + optimal repairs for unaffected children
    direct_cost := COMPUTE_COST(v)  // Cost of recomputing node v
    children := CHILDREN(v)
    unaffected_cost := 0.0
    unaffected_actions := ∅

    for each c ∈ children do
      if ANNIHILATE(OPERATOR(c), PUSH_DELTA(OPERATOR(c), δ_v)):
        // Child is unaffected by repair at v
        (child_cost, child_actions) := memo[c]
        unaffected_cost += child_cost
        unaffected_actions := unaffected_actions ∪ child_actions

    option1_cost := direct_cost + unaffected_cost
    option1_actions := {RECOMPUTE(v)} ∪ unaffected_actions

    // Option 2: Optimal repairs for all children
    all_children_cost := 0.0
    all_children_actions := ∅

    for each c ∈ children do
      (child_cost, child_actions) := memo[c]
      all_children_cost += child_cost
      all_children_actions := all_children_actions ∪ child_actions

    // Choose minimum cost option
    if option1_cost ≤ all_children_cost:
      memo[v] := (option1_cost, option1_actions)
    else:
      memo[v] := (all_children_cost, all_children_actions)

  // Return repair plan for root nodes
  total_cost := 0.0
  total_actions := ∅
  roots := FIND_ROOTS(G)

  for each r ∈ roots do
    (cost, actions) := memo[r]
    total_cost += cost
    total_actions := total_actions ∪ actions

  return REPAIR_PLAN(total_cost, total_actions)

ALGORITHM LP_REPAIR(G, Δ):
  // Variables: x_v ∈ [0,1] for each node v (repair probability)
  variables := {x_v | v ∈ V}

  // Objective: minimize total repair cost
  objective := minimize Σ_{v∈V} COMPUTE_COST(v) · x_v

  constraints := []

  // Coverage constraints: if node has non-zero delta, it or its children must be repaired
  for each v ∈ V do
    δ_v := Δ[v]
    if δ_v ≠ (ε_S, 0_D, ⊥_Q) and not ANNIHILATE(OPERATOR(v), δ_v):
      children := CHILDREN(v)
      constraints.append(x_v + Σ_{c∈children} x_c ≥ 1)

  // Dependency constraints: if parent is not repaired, all affected children must be
  for each (u,v) ∈ E do
    δ_u := Δ[u]
    if δ_u ≠ (ε_S, 0_D, ⊥_Q):
      pushed_delta := PUSH_DELTA(OPERATOR(v), δ_u)
      if not ANNIHILATE(OPERATOR(v), pushed_delta):
        constraints.append(x_v ≥ (1 - x_u))  // If u not repaired, v must be

  // Solve LP relaxation
  lp_solution := SOLVE_LP(objective, constraints, variables)

  // Randomized rounding
  repair_actions := ∅
  for each v ∈ V do
    prob := lp_solution[x_v]
    if RANDOM() ≤ prob:
      repair_actions := repair_actions ∪ {RECOMPUTE(v)}

  // Ensure coverage with greedy patch
  uncovered := FIND_UNCOVERED_NODES(G, Δ, repair_actions)
  for each v ∈ uncovered do
    repair_actions := repair_actions ∪ {RECOMPUTE(v)}

  total_cost := Σ_{RECOMPUTE(v)∈repair_actions} COMPUTE_COST(v)
  return REPAIR_PLAN(total_cost, repair_actions)

ALGORITHM VERIFY_FRAGMENT_F(G):
  // Check each stage for fragment F compliance
  for each v ∈ V(G) do
    sql_ast := PARSE_SQL(QUERY(v))

    if not CHECK_DETERMINISTIC(sql_ast):
      return (false, f"Node {v} violates determinism: {GET_VIOLATION_REASON(sql_ast)}")

    if not CHECK_EXACT_ARITHMETIC(sql_ast):
      return (false, f"Node {v} uses floating-point arithmetic")

    if not CHECK_SUPPORTED_OPERATORS(sql_ast):
      return (false, f"Node {v} uses unsupported operator: {GET_UNSUPPORTED_OP(sql_ast)}")

  return (true, "Pipeline is in Fragment F")

SUBROUTINE CHECK_DETERMINISTIC(ast):
  // Traverse AST for non-deterministic constructs
  for each node ∈ TRAVERSE_AST(ast) do
    if node.type == ORDER_BY:
      if not HAS_UNIQUE_ORDERING(node):
        return false  // ORDER BY with ties

    if node.type == LIMIT:
      if not HAS_DETERMINISTIC_ORDER(PARENT(node)):
        return false  // LIMIT without unique ordering

    if node.type == FUNCTION_CALL:
      func_name := node.function_name
      if func_name ∈ {RAND, RANDOM, NOW, CURRENT_TIMESTAMP, ROW_NUMBER}:
        if func_name == ROW_NUMBER and not HAS_DETERMINISTIC_ORDER(node):
          return false
        elif func_name ≠ ROW_NUMBER:
          return false  // Other non-deterministic functions

    if node.type == EXTERNAL_CALL:
      return false  // UDFs, external data sources

  return true

SUBROUTINE CHECK_EXACT_ARITHMETIC(ast):
  for each node ∈ TRAVERSE_AST(ast) do
    if node.type == COLUMN_TYPE:
      if node.sql_type ∈ {FLOAT, DOUBLE, REAL}:
        return false  // Floating-point types

    if node.type == FUNCTION_CALL:
      func_name := node.function_name
      if func_name ∈ {AVG, STDDEV, VARIANCE, CORR}:
        return false  // Statistical aggregates with rounding

  return true

SUBROUTINE CHECK_SUPPORTED_OPERATORS(ast):
  supported_ops := {SELECT, FROM, WHERE, JOIN, GROUP_BY, HAVING, UNION, INTERSECT, EXCEPT, WITH}

  for each node ∈ TRAVERSE_AST(ast) do
    if node.type == SQL_OPERATOR:
      if node.operator ∉ supported_ops:
        return false

  return true
